var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"오늘부터 드레카는 마트료시카 인형을 만드는 수술을 집도하기로 했어.","JPN":"今日からドレカは、マトリョシカ人形を作る手術を執刀することになったよ。","ENG":"Starting today, Dreka will be in charge of performing the surgery to make Matryoshka Dolls.","TWN":"從今天起，德蕾卡決定主刀俄羅斯娃娃手術。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"친구들로 많이 연습했으니까, 이젠 나도 잘할 수 있을 거야.","JPN":"お友だちでいっぱい練習したから、私も上手にできるはずなの。","ENG":"Since I had a lot of practice on my friends, I'm certain I can do it well.","TWN":"因為和朋友們練習了很多遍，現在我也可以做得到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"너무 아파하네… 고통을 줄일 방법은 없을까?","JPN":"すごく苦しがってる……苦痛を減らす方法はないかな？","ENG":"She's hurting so much... Is there a way to help ease her pain?","TWN":"她好像很痛……有沒有減輕痛苦的方法？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"음… 맞다! 마취라는 게 있었구나!","JPN":"うーん……そうだ！　麻酔ってものがあったんだね！","ENG":"Um... Oh! There's a thing called anesthesia!","TWN":"嗯……對了！還有麻醉這種東西啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"히힛, 이제 기억했으니까, 더 이상 아파하는 친구들은 없을 거야.","JPN":"ひひっ、もう覚えたから、苦しがるお友だちはいないはずだよ。","ENG":"Hehe. Now that I remember, my friends won't be in pain anymore.","TWN":"嘿嘿，現在記起來了，朋友們不會再感到疼痛了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"지금까지 죽은 친구들… 너무 불쌍해.","JPN":"今まで死んだお友だち……とても可哀想。","ENG":"But I feel sorry for my friends that have already died...","TWN":"不過之前死去的朋友們……太可憐了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"대신 친구들이 몇 명인지 영원히 기억해주기로 했어.","JPN":"その代わり、お友だちが何人だったか永遠に覚えてあげることにしたの。","ENG":"Instead, I decided to remember how many were sacrificed forever.","TWN":"所以我決定永遠記住朋友們的數量。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"히힛, 그게 내가 속죄할 수 있는 유일한 방법이겠지?","JPN":"ひひっ、それが私が罪を償う唯一の方法だよね？","ENG":"Hehe, I guess you can say it's my way of atoning.","TWN":"嘿嘿，這大概是我唯一能贖罪的方式吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"수술은 무사히 끝났어. 나도 이제 박사님처럼 똑똑한 사람♪","JPN":"手術は無事終わったよ。私も博士みたいな賢い人ね♪","ENG":"The surgery was a success. Now, I'm just as smart as the doctor♪","TWN":"手術順利結束了，我現在也是像博士一樣聰明的人了♪"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"그럼 이제 기록해볼까?","JPN":"じゃあ、記録してみようかな？","ENG":"I should log it now.","TWN":"那麼現在開始記錄吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"……어라?","JPN":"……あれ？","ENG":"...Huh?","TWN":"……咦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"지금까지… 몇 명이었더라…?","JPN":"今まで……何人だったっけ……？","ENG":"How many... was it until now...?","TWN":"到現在為止……總共有多少人……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>나… 져버린 거야?</color>","JPN":"<color=#ffd34c>私……負けちゃったの？</color>","ENG":"<color=#ffd34c>I... lost?</color>","TWN":"<color=#ffd34c>我……竟然輸了？</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>흐응… 아쉬워라.</color>","JPN":"<color=#ffd34c>ふーん……残念。</color>","ENG":"<color=#ffd34c>Hmm... That's a shame.</color>","TWN":"<color=#ffd34c>……真可惜。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>뭐해? 마무리 지어야지.</color>","JPN":"<color=#ffd34c>何してるの？　とどめを刺して。</color>","ENG":"<color=#ffd34c>What are you waiting for? Finish the job.</color>","TWN":"<color=#ffd34c>在幹什麼？結束這一切吧。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"너의 메모리 코어는 파괴되었어. 죽는 건 시간문제야.","JPN":"あなたのメモリーコアは破壊された。死ぬのは時間の問題だよ。","ENG":"Your memory core has been destroyed. It's only a matter of time that you die.","TWN":"你的記憶核心已經被破壞，死亡只是時間問題。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>후훗. 그렇구나…</color>","JPN":"<color=#ffd34c>ふふっ。そっか……</color>","ENG":"<color=#ffd34c>Hehe. I see...</color>","TWN":"<color=#ffd34c>嘿嘿，是嗎……</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>난… 이제 죽는 거구나…</color>","JPN":"<color=#ffd34c>私……もう死ぬんだ……</color>","ENG":"<color=#ffd34c>So... I'm really going to die this time...</color>","TWN":"<color=#ffd34c>我……要死了嗎……</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>정말 슬퍼… 우리가 함께였으면 더 좋았을 텐데…</color>","JPN":"<color=#ffd34c>本当に悲しいなあ……私たちが一緒だったらもっとよかったのに……</color>","ENG":"<color=#ffd34c>It's so sad... We could've had fun together...</color>","TWN":"<color=#ffd34c>真的好難過……如果我們能在一起就好了……</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>언니와 함께라면… 더 행복한 하루가 기다리고 있었을 텐데…</color>","JPN":"<color=#ffd34c>マブカさんと一緒なら……もっと幸せな日々が待ってたはずなのに……</color>","ENG":"<color=#ffd34c>With you... a happier tomorrow was waiting for us...</color>","TWN":"<color=#ffd34c>如果和姊姊在一起……一定會有更幸福的一天吧……</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>행복해지기 위해서… 언니와 함께 참고 또 참아왔는데…</color>","JPN":"<color=#ffd34c>幸せになるために……姉さんと一緒にずっと我慢し続けたのに……</color>","ENG":"<color=#ffd34c>It was all to be happy... That's why you and I endured all this...</color>","TWN":"<color=#ffd34c>為了幸福……我和姊姊一直在忍耐……</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>왜… 이렇게 죽어야 하는 거야…?</color>","JPN":"<color=#ffd34c>どうして……こんなふうに死なないといけないの……？</color>","ENG":"<color=#ffd34c>But why... Why do I have to die like this...?</color>","TWN":"<color=#ffd34c>為什麼……要這樣死去……？</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"너무 추워… 이게 죽는다는 건가…?","JPN":"すごく寒い……これが死ぬってこと……？","ENG":"It's so cold... Is this what it means to die...?","TWN":"好冷……這就是死亡嗎……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"지금까지 내가 죽여온 아이들의 모습이…","JPN":"今まで私が殺してきた子どもたちの姿が……","ENG":"All the kids that I've killed so far...","TWN":"死去的朋友們的樣子……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"주마등처럼 스쳐 지나가고 있네.","JPN":"走馬灯のように過ぎ去るね。","ENG":"They are flashing before my eyes.","TWN":"像走馬燈一樣閃過。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"후훗… 지금까지 몇 명이었는지… 이젠 기억할 수 있겠어.","JPN":"ふふっ……今まで何人だったか……やっと思い出せる。","ENG":"Haha... I now remember... how many it was.","TWN":"嘿嘿…哪還記得…到底有多少人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"난 어디로 가는걸까? 책에선 천국과 지옥이 있다고 했는데…","JPN":"私はどこに行くんだろう？　本では天国と地獄があるって書いてあったけど……","ENG":"Where do you think I'll go? I read in books that there's a heaven and hell...","TWN":"我會去哪裡呢？書上說有天堂和地獄……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"아픈 곳은 싫어… 드레카는 천국에 가고 싶어….","JPN":"苦しむところはイヤ……ドレカは天国に行きたい……","ENG":"I don't like places that cause pain... Dreka wants to go to heaven...","TWN":"不想去痛苦的地方……德蕾卡想去天堂……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"드레카는 말 잘 듣는 착한 아이였으니까, 분명 갈 수 있을 거야.","JPN":"ドレカは言うことをよく聞くいい子だったから、きっと行けるよ。","ENG":"Because Dreka was a good girl, I'm sure I'll go to heaven.","TWN":"因為德蕾卡是聽話的好孩子，一定能去的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"그렇지? 언니…?","JPN":"ね？　姉さん……？","ENG":"Isn’t that right? Eva...?","TWN":"是吧？姊姊……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};